// Extract WhatsApp webhook payload
const body = $input.item.json.body || $input.item.json;

// WhatsApp Business API typically sends messages in this format
const entry = body.entry?.[0] || {};
const changes = entry.changes?.[0] || {};
const value = changes.value || {};
const messages = value.messages || [body]; // Fallback for direct message format

// Process all messages in the batch
const processedMessages = [];
const mediaItems = [];
const locations = [];

for (const msg of messages) {
  const messageData = {
    messageId: msg.id || `msg-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    from: msg.from || body.from || 'UNKNOWN_USER',
    timestamp: msg.timestamp || body.timestamp || Date.now(),
    type: msg.type || body.type || 'text'
  };

  // Parse message content based on type
  if (msg.type === 'text' || body.text) {
    messageData.text = msg.text?.body || body.text || '';
    processedMessages.push(messageData);
  } 
  else if (msg.type === 'image' || body.image) {
    const image = msg.image || body.image || {};
    mediaItems.push({
      ...messageData,
      mediaType: 'image',
      mediaId: image.id,
      caption: image.caption || '',
      mimeType: image.mime_type || 'image/jpeg',
      sha256: image.sha256 || null
    });
  }
  else if (msg.type === 'location' || body.location) {
    const loc = msg.location || body.location || {};
    locations.push({
      ...messageData,
      latitude: loc.latitude,
      longitude: loc.longitude,
      name: loc.name || 'Unknown Location',
      address: loc.address || ''
    });
  }
  else if (msg.type === 'video' || body.video) {
    const video = msg.video || body.video || {};
    mediaItems.push({
      ...messageData,
      mediaType: 'video',
      mediaId: video.id,
      caption: video.caption || '',
      mimeType: video.mime_type || 'video/mp4'
    });
  }
}

// If this is a simple single message format (not WhatsApp API format)
if (processedMessages.length === 0 && mediaItems.length === 0 && body.message) {
  processedMessages.push({
    messageId: `msg-${Date.now()}`,
    from: body.phone || body.userId || 'USER',
    timestamp: Date.now(),
    type: 'text',
    text: body.message
  });
}

// Add any photos from direct uploads
if (body.photos && Array.isArray(body.photos)) {
  body.photos.forEach((photo, idx) => {
    mediaItems.push({
      messageId: `photo-${Date.now()}-${idx}`,
      from: body.phone || body.userId || 'USER',
      timestamp: Date.now(),
      type: 'image',
      mediaType: 'image',
      mediaUrl: photo.url || photo,
      caption: photo.caption || ''
    });
  });
}

// Add location if provided directly
if (body.location) {
  locations.push({
    messageId: `loc-${Date.now()}`,
    from: body.phone || body.userId || 'USER',
    timestamp: Date.now(),
    type: 'location',
    latitude: body.location.lat || body.location.latitude,
    longitude: body.location.lng || body.location.longitude,
    name: body.location.name || 'Current Location',
    address: body.location.address || ''
  });
}

// Determine travel day (group by date in user's timezone)
const firstTimestamp = processedMessages[0]?.timestamp || mediaItems[0]?.timestamp || Date.now();
const messageDate = new Date(parseInt(firstTimestamp) * 1000 || firstTimestamp);
const travelDay = messageDate.toISOString().split('T')[0]; // YYYY-MM-DD

// Extract user identifier
const userId = body.userId || processedMessages[0]?.from || 'DEFAULT_USER';
const tripId = body.tripId || `TRIP-${travelDay}`;

// Build aggregated journal entry
const journalEntry = {
  // Identifiers
  entryId: `ENTRY-${Date.now()}-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
  userId: userId,
  tripId: tripId,
  travelDay: travelDay,

  // Content
  messages: processedMessages.sort((a, b) => a.timestamp - b.timestamp),
  media: mediaItems.sort((a, b) => a.timestamp - b.timestamp),
  locations: locations,

  // Metadata
  totalMessages: processedMessages.length,
  totalMedia: mediaItems.length,
  totalLocations: locations.length,
  dayStartTime: messageDate.toISOString(),

  // Context
  timezone: body.timezone || 'UTC',
  destination: body.destination || locations[0]?.name || 'Unknown',
  tripName: body.tripName || `Journey to ${locations[0]?.name || 'Unknown'}`,

  // Processing
  receivedAt: new Date().toISOString(),
  status: 'VALIDATED'
};

// Validation
if (journalEntry.totalMessages === 0 && journalEntry.totalMedia === 0) {
  throw new Error('No valid messages or media found in WhatsApp payload');
}

return { json: { journalEntry } };

// Get journal entry from validation step
const journalEntry = $('JS #1: Validate & Aggregate Messages').item.json.journalEntry;

// Get previous journal data (if exists)
const previousJournals = $('Fetch Previous Journal Entries').all().map(i => i.json);
const hasPreviousEntries = previousJournals.length > 0;

// Build chronological timeline of the day
const timeline = [];

// Add all messages
journalEntry.messages.forEach(msg => {
  const time = new Date(parseInt(msg.timestamp) * 1000 || msg.timestamp);
  timeline.push({
    time: time.toISOString(),
    timeFormatted: time.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }),
    type: 'message',
    content: msg.text
  });
});

// Add all media with captions
journalEntry.media.forEach(media => {
  const time = new Date(parseInt(media.timestamp) * 1000 || media.timestamp);
  timeline.push({
    time: time.toISOString(),
    timeFormatted: time.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }),
    type: media.mediaType,
    content: media.caption || `[${media.mediaType} - ${media.mediaId || 'uploaded'}]`,
    mediaId: media.mediaId,
    mediaUrl: media.mediaUrl || null
  });
});

// Add all locations
journalEntry.locations.forEach(loc => {
  const time = new Date(parseInt(loc.timestamp) * 1000 || loc.timestamp);
  timeline.push({
    time: time.toISOString(),
    timeFormatted: time.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }),
    type: 'location',
    content: `📍 ${loc.name}${loc.address ? ' - ' + loc.address : ''}`,
    coordinates: `${loc.latitude}, ${loc.longitude}`
  });
});

// Sort timeline chronologically
timeline.sort((a, b) => new Date(a.time) - new Date(b.time));

// Build formatted timeline text for AI
const timelineText = timeline.map(item => 
  `${item.timeFormatted} - ${item.content}`
).join('\n');

// Extract locations for context
const visitedLocations = journalEntry.locations.map(l => l.name).filter(Boolean);
const primaryLocation = visitedLocations[0] || journalEntry.destination;

// Count media for AI awareness
const photoCount = journalEntry.media.filter(m => m.mediaType === 'image').length;
const videoCount = journalEntry.media.filter(m => m.mediaType === 'video').length;

// Build context object for AI
const aiContext = {
  journalEntry,
  timeline,
  timelineText,
  primaryLocation,
  visitedLocations,
  photoCount,
  videoCount,
  hasPreviousEntries,
  previousJournalCount: previousJournals.length,
  previousJournalLink: previousJournals[0]?.webViewLink || null,

  // Metadata for AI
  travelDayFormatted: new Date(journalEntry.travelDay).toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  }),

  // Instructions for AI
  storyPrompt: {
    tripName: journalEntry.tripName,
    dayNumber: hasPreviousEntries ? previousJournals.length + 1 : 1,
    destination: primaryLocation,
    messageCount: journalEntry.totalMessages,
    hasPhotos: photoCount > 0,
    hasVideos: videoCount > 0,
    hasLocations: journalEntry.totalLocations > 0
  }
};

return [{ json: aiContext }];

const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle Anthropic content array format
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Strip markdown code blocks
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let story;
try {
  story = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse Claude story response: ${error.message}. Raw: ${cleanText.substring(0, 200)}`);
}

// Get context from previous steps
const aiContext = $('JS #2: Prepare AI Context').item.json;
const journalEntry = aiContext.journalEntry;

// Build complete journal record
const journalRecord = {
  // Story content
  title: story.title,
  story: story.story,
  highlights: story.highlights || [],
  locations: story.locations || aiContext.visitedLocations,
  mood: story.mood || 'reflective',
  tags: story.tags || [],
  photoMoments: story.photoMoments || [],
  tomorrowAnticipation: story.tomorrowAnticipation || '',
  wordCount: story.wordCount || 0,

  // Original data
  entryId: journalEntry.entryId,
  tripId: journalEntry.tripId,
  travelDay: journalEntry.travelDay,
  dayNumber: aiContext.storyPrompt.dayNumber,

  // Metadata
  messageCount: journalEntry.totalMessages,
  photoCount: aiContext.photoCount,
  videoCount: aiContext.videoCount,
  locationCount: journalEntry.totalLocations,

  // Timeline
  timeline: aiContext.timeline,

  // Processing info
  generatedAt: new Date().toISOString(),
  aiModel: 'claude-sonnet-4-20250514',
  status: 'GENERATED'
};

return { json: { journalRecord, rawStory: story } };

const record = $input.item.json.journalRecord;

// Format story with proper paragraphs and spacing
const formattedStory = record.story.replace(/\\n\\n/g, '\n\n').trim();

// Build complete document content
const documentContent = `${record.title}
${'='.repeat(record.title.length)}

Date: ${new Date(record.travelDay).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
Day ${record.dayNumber} of ${record.tripId}
Mood: ${record.mood}
Locations: ${record.locations.join(', ')}

${'-'.repeat(80)}

${formattedStory}

${'-'.repeat(80)}

📌 HIGHLIGHTS OF THE DAY
${record.highlights.map((h, i) => `${i + 1}. ${h}`).join('\n')}

📸 PHOTO MOMENTS (${record.photoCount} photos)
${record.photoMoments.map((p, i) => `${i + 1}. ${p}`).join('\n')}

📍 LOCATIONS VISITED
${record.locations.map((l, i) => `${i + 1}. ${l}`).join('\n')}

🏷️ TAGS
${record.tags.join(', ')}

💭 TOMORROW
${record.tomorrowAnticipation || 'To be continued...'}

${'-'.repeat(80)}

Journal Entry ID: ${record.entryId}
Generated: ${new Date(record.generatedAt).toLocaleString()}
AI Model: ${record.aiModel}
Word Count: ${record.wordCount} words
Messages Processed: ${record.messageCount}
Media Included: ${record.photoCount} photos, ${record.videoCount} videos
Locations Tracked: ${record.locationCount}
`;

// Prepare for Google Drive
const fileName = `${record.tripId}_Day_${record.dayNumber}_${record.travelDay}.txt`;
const fileTitle = `${record.title} - ${record.travelDay}`;

return {
  json: {
    journalRecord: record,
    documentContent,
    fileName,
    fileTitle,

    // Preview for notification
    preview: `${record.title}\n\n${formattedStory.substring(0, 200)}...`,

    // Stats summary
    summary: {
      title: record.title,
      dayNumber: record.dayNumber,
      date: record.travelDay,
      wordCount: record.wordCount,
      highlights: record.highlights.length,
      locations: record.locations.length,
      photos: record.photoCount
    }
  }
};

const formatted = $('JS #3: Format Document').item.json;
const driveDoc = $('Create/Update Google Doc').item.json;

return {
  json: {
    success: true,
    message: 'Travel journal entry generated and saved successfully!',
    journalEntry: {
      id: formatted.journalRecord.entryId,
      title: formatted.summary.title,
      dayNumber: formatted.summary.dayNumber,
      date: formatted.summary.date,
      wordCount: formatted.summary.wordCount
    },
    document: {
      name: formatted.fileName,
      id: driveDoc.id || 'processing',
      link: driveDoc.webViewLink || 'will be available shortly'
    },
    stats: formatted.summary,
    processedAt: new Date().toISOString()
  }
};
